- "sprouting new inhabitants like flowers in the spring" metaphorically refers to regions experiencing population growth;
- "economic hardships" here refers to the average poverty rates over the years 2010 to 2015;
- "rental housing landscapes" reflects the percentage of households occupied by renters in 2015.

sql:
SELECT AVG(rent_burden) AS average_rent_burden
FROM rent_burden
WHERE rent_burden > (SELECT AVG(rent_burden) FROM rent_burden);

SELECT regions.region_name, years.year_name
FROM regions
INNER JOIN years ON regions.region_id = years.year_id;

SELECT median_household_income
FROM median_household_income
WHERE year_id = 1;

SELECT regions.region_name, eviction_filings.eviction_filing_rate
FROM regions
INNER JOIN eviction_filings ON regions.region_id = eviction_filings.region_id;

SELECT region_id, population_count
FROM population
WHERE population_count = (SELECT MAX(population_count) FROM population);

SELECT year_name 
FROM years 
WHERE year_id = 0;

SELECT region_id, poverty_rate, LN(poverty_rate), SINH(poverty_rate)
FROM poverty_rates
WHERE region_id = 0;

SELECT filing_id, region_id, eviction_filings
FROM eviction_filings
WHERE filing_id = 1 AND region_id = 0 AND year_id = 1;

SELECT region_id, population_count
FROM population
WHERE region_id = 0;

SELECT year_id, eviction_filings 
FROM eviction_filings 
WHERE region_id = 0;

SELECT regions.region_name
FROM regions
JOIN racial_demographics ON regions.region_id = racial_demographics.region_id
WHERE racial_demographics.pct_white = (
    SELECT MAX(pct_white) FROM racial_demographics
);
